#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    const long long LIM = 1000000LL;
    while(T--){
        long long X; scanf("%lld",&X);
        if(X==1){
            printf("-1\n");
            continue;
        }
        long long A,B,C;
        if(X<=LIM+1){
            A = X-1; B = 1; C = 1;
        }else{
            A = LIM;
            B = (X-1)/LIM;
            C = X - A*B;
        }
        printf("%lld %lld %lld\n",A,B,C);
    }
    return 0;
}

