const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
const LIM = 1000000;
let res = [];
for(let t = 0; t < T; t++){
  const X = Number(input[idx++]);
  if (X === 1){
    res.push('-1');
    continue;
  }
  let A, B, C;
  if (X <= LIM + 1){
    A = X - 1;
    B = 1;
    C = 1;
  } else {
    A = LIM;
    B = Math.floor((X - 1) / LIM);
    C = X - A * B;
  }
  res.push(`${A} ${B} ${C}`);
}
console.log(res.join('\n'));
